-- Project Harborlight Phase 1. Apply after 0004; 0005 is reserved by parallel candidates.
-- MySQL parity uses the same additive columns/tables as SQLite, with VARCHAR(191) IDs and LONGTEXT snapshots.
CREATE TABLE `CommunityProfile` (`id` VARCHAR(191) NOT NULL, `accountId` VARCHAR(191) NOT NULL, `normalizedHandle` VARCHAR(191) NOT NULL, `handle` VARCHAR(191) NOT NULL, `displayName` VARCHAR(191) NOT NULL, `biography` TEXT NULL, `visibility` VARCHAR(32) NOT NULL DEFAULT 'COMMUNITY', `creatorStatus` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE', `moderationStatus` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE', `verificationStatus` VARCHAR(32) NOT NULL DEFAULT 'UNVERIFIED', `supportedLanguages` LONGTEXT NOT NULL, `socialLinks` LONGTEXT NOT NULL, `lastPublishedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, UNIQUE INDEX `CommunityProfile_accountId_key`(`accountId`), UNIQUE INDEX `CommunityProfile_normalizedHandle_key`(`normalizedHandle`), INDEX `CommunityProfile_moderationStatus_visibility_idx`(`moderationStatus`,`visibility`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityListing` (`id` VARCHAR(191) NOT NULL, `slug` VARCHAR(191) NOT NULL, `itemType` VARCHAR(64) NOT NULL, `ownerProfileId` VARCHAR(191) NOT NULL, `title` VARCHAR(191) NOT NULL, `shortDescription` TEXT NULL, `longDescription` LONGTEXT NULL, `visibility` VARCHAR(32) NOT NULL DEFAULT 'PRIVATE', `publicationStatus` VARCHAR(32) NOT NULL DEFAULT 'DRAFT', `moderationStatus` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE', `spoilerLevel` VARCHAR(32) NOT NULL DEFAULT 'PREVIEW_SAFE', `locationClass` VARCHAR(32) NOT NULL DEFAULT 'FICTIONAL', `primaryCategory` VARCHAR(191) NULL, `tags` LONGTEXT NOT NULL, `contentWarnings` LONGTEXT NOT NULL, `currentReleaseId` VARCHAR(191) NULL, `publishedAt` DATETIME(3) NULL, `archivedAt` DATETIME(3) NULL, `removedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, UNIQUE INDEX `CommunityListing_slug_key`(`slug`), UNIQUE INDEX `CommunityListing_currentReleaseId_key`(`currentReleaseId`), INDEX `CommunityListing_ownerProfileId_updatedAt_idx`(`ownerProfileId`,`updatedAt`), INDEX `CommunityListing_publicationStatus_visibility_idx`(`publicationStatus`,`visibility`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityRelease` (`id` VARCHAR(191) NOT NULL, `listingId` VARCHAR(191) NOT NULL, `semanticVersion` VARCHAR(64) NOT NULL, `manifestSchemaVersion` INTEGER NOT NULL DEFAULT 1, `minimumPlatformVersion` VARCHAR(64) NULL, `sourcePublishedTaleVersionId` VARCHAR(191) NULL, `manifest` LONGTEXT NOT NULL, `manifestChecksum` VARCHAR(191) NOT NULL, `packageChecksum` VARCHAR(191) NULL, `releaseNotes` TEXT NULL, `compatibility` LONGTEXT NOT NULL, `licenseSnapshot` LONGTEXT NOT NULL, `attributionSnapshot` LONGTEXT NOT NULL, `spoilerSnapshot` LONGTEXT NOT NULL, `moderationStatus` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE', `publishedByProfileId` VARCHAR(191) NOT NULL, `publishedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `deprecatedAt` DATETIME(3) NULL, `replacementReleaseId` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), UNIQUE INDEX `CommunityRelease_listingId_semanticVersion_key`(`listingId`,`semanticVersion`), INDEX `CommunityRelease_listingId_publishedAt_idx`(`listingId`,`publishedAt`), INDEX `CommunityRelease_sourcePublishedTaleVersionId_idx`(`sourcePublishedTaleVersionId`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityReleaseAttribution` (`id` VARCHAR(191) NOT NULL, `releaseId` VARCHAR(191) NOT NULL, `creditedProfileId` VARCHAR(191) NULL, `creditedDisplayName` VARCHAR(191) NOT NULL, `contributionType` VARCHAR(64) NOT NULL, `sourceUrl` TEXT NULL, `requiredCreditText` TEXT NULL, `licenseReference` VARCHAR(191) NULL, `sortOrder` INTEGER NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `CommunityReleaseAttribution_releaseId_sortOrder_idx`(`releaseId`,`sortOrder`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityOwnershipDeclaration` (`id` VARCHAR(191) NOT NULL, `listingId` VARCHAR(191) NOT NULL, `releaseId` VARCHAR(191) NULL, `declarantProfileId` VARCHAR(191) NOT NULL, `declarationVersion` INTEGER NOT NULL, `acceptedStatements` LONGTEXT NOT NULL, `evidenceReferences` LONGTEXT NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `CommunityOwnershipDeclaration_listingId_releaseId_idx`(`listingId`,`releaseId`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityAssetReference` (`id` VARCHAR(191) NOT NULL, `ownerProfileId` VARCHAR(191) NOT NULL, `releaseId` VARCHAR(191) NULL, `checksum` VARCHAR(191) NOT NULL, `declaredMimeType` VARCHAR(191) NOT NULL, `detectedMimeType` VARCHAR(191) NULL, `fileSize` INTEGER NOT NULL, `storageProvider` VARCHAR(64) NOT NULL, `storageKey` VARCHAR(191) NOT NULL, `visibility` VARCHAR(32) NOT NULL DEFAULT 'PRIVATE', `scanStatus` VARCHAR(32) NOT NULL DEFAULT 'SCAN_NOT_CONFIGURED', `processingStatus` VARCHAR(32) NOT NULL DEFAULT 'UPLOADED', `accessibility` LONGTEXT NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, `removedAt` DATETIME(3) NULL, UNIQUE INDEX `CommunityAssetReference_storageKey_key`(`storageKey`), UNIQUE INDEX `CommunityAssetReference_ownerProfileId_checksum_key`(`ownerProfileId`,`checksum`), INDEX `CommunityAssetReference_releaseId_visibility_idx`(`releaseId`,`visibility`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityOutboxEvent` (`id` VARCHAR(191) NOT NULL, `eventType` VARCHAR(128) NOT NULL, `aggregateType` VARCHAR(64) NOT NULL, `aggregateId` VARCHAR(191) NOT NULL, `payloadVersion` INTEGER NOT NULL DEFAULT 1, `payload` LONGTEXT NOT NULL, `idempotencyKey` VARCHAR(191) NOT NULL, `availableAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `claimedAt` DATETIME(3) NULL, `processedAt` DATETIME(3) NULL, `attemptCount` INTEGER NOT NULL DEFAULT 0, `terminalFailureAt` DATETIME(3) NULL, `failureCode` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), UNIQUE INDEX `CommunityOutboxEvent_idempotencyKey_key`(`idempotencyKey`), INDEX `CommunityOutboxEvent_processedAt_availableAt_idx`(`processedAt`,`availableAt`), INDEX `CommunityOutboxEvent_aggregateType_aggregateId_createdAt_idx`(`aggregateType`,`aggregateId`,`createdAt`), PRIMARY KEY (`id`));
CREATE TABLE `CommunityLicensePolicy` (`id` VARCHAR(191) NOT NULL, `key` VARCHAR(191) NOT NULL, `displayName` VARCHAR(191) NOT NULL, `policyVersion` INTEGER NOT NULL DEFAULT 1, `allowsPrivateUse` BOOLEAN NOT NULL DEFAULT true, `allowsPublicUse` BOOLEAN NOT NULL DEFAULT false, `allowsModification` BOOLEAN NOT NULL DEFAULT false, `allowsRedistribution` BOOLEAN NOT NULL DEFAULT false, `allowsCommercialUse` BOOLEAN NOT NULL DEFAULT false, `requiresAttribution` BOOLEAN NOT NULL DEFAULT true, `requiresSourceLink` BOOLEAN NOT NULL DEFAULT false, `shareAlike` BOOLEAN NOT NULL DEFAULT false, `customTerms` TEXT NULL, `termsUrl` TEXT NULL, `active` BOOLEAN NOT NULL DEFAULT true, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, UNIQUE INDEX `CommunityLicensePolicy_key_key`(`key`), PRIMARY KEY (`id`));
